import{c as a,Q as n,j as i,m as l}from"./chunks/framework.Bhbi9jCp.js";const k=JSON.parse('{"title":"程序的生命周期","description":"","frontmatter":{},"headers":[],"relativePath":"osLearning/03-程序的生命周期.md","filePath":"osLearning/03-程序的生命周期.md","lastUpdated":1781095972000}'),e={name:"osLearning/03-程序的生命周期.md"};function t(p,s,h,o,r,d){return n(),i("div",null,[...s[0]||(s[0]=[l(`<h1 id="程序的生命周期" tabindex="-1">程序的生命周期 <a class="header-anchor" href="#程序的生命周期" aria-label="Permalink to &quot;程序的生命周期&quot;">​</a></h1><p><code>gcc hello.c -o hello &amp;&amp; ./hello</code>——看起来一行命令的事,背后是 OS 最长的一条流水线:预处理、编译、汇编、链接、装载、动态链接、初始化,最后才轮到你的 main()。大多数人对它的认知是&quot;反正它能跑&quot;,直到某天翻车:链接器报 undefined reference、程序 scp 到另一台机器就缺 .so、GDB 里断点地址每次都不一样。这些问题全出在&quot;main 之前&quot;的世界里,<strong>而 99% 的程序员从来没看过这个世界</strong>。这一篇带你走完全程——理解了它,后面的内存布局、共享库、容器镜像、core dump 分析,全是这一篇的延伸。</p><blockquote><p>一句话先记住:<strong>程序的一生 = 编译期(源码 → ELF 文件)+ 运行期(execve → 装载 → 动态链接 → 初始化 → main)</strong>。<strong>ELF 是 Linux 世界&quot;程序长什么样&quot;的统一标准</strong>——可执行文件、共享库、core dump 全是 ELF。搞懂 ELF 一种格式,三类文件全通。</p></blockquote><hr><h2 id="一、全景-八步走" tabindex="-1">一、全景:八步走 <a class="header-anchor" href="#一、全景-八步走" aria-label="Permalink to &quot;一、全景:八步走&quot;">​</a></h2><p>先把地图铺开,后面逐段放大:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>源代码 (hello.c)</span></span>
<span class="line"><span>   ↓ 预处理 (cpp)</span></span>
<span class="line"><span>预处理后的源代码 (hello.i)</span></span>
<span class="line"><span>   ↓ 编译 (cc1)</span></span>
<span class="line"><span>汇编代码 (hello.s)</span></span>
<span class="line"><span>   ↓ 汇编 (as)</span></span>
<span class="line"><span>目标文件 (hello.o)</span></span>
<span class="line"><span>   ↓ 链接 (ld)</span></span>
<span class="line"><span>可执行文件 (hello, ELF 格式)</span></span>
<span class="line"><span>   ↓ execve syscall</span></span>
<span class="line"><span>内核装载到内存</span></span>
<span class="line"><span>   ↓ 转交动态链接器</span></span>
<span class="line"><span>动态库映射 + 符号解析</span></span>
<span class="line"><span>   ↓ 初始化(.init / 全局对象构造)</span></span>
<span class="line"><span>main() 被调用</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>程序运行</span></span>
<span class="line"><span>   ↓ exit / _exit</span></span>
<span class="line"><span>进程结束</span></span></code></pre></div><p><strong>前 4 步是编译期</strong>(产物是硬盘上的一个 ELF 文件),<strong>后 4 步是运行期</strong>(把 ELF 变成内存里的活进程)。两个世界的交接点就是 <code>execve</code>——后面会细讲。</p><hr><h2 id="二、elf-linux-的-程序标准格式" tabindex="-1">二、ELF:Linux 的&quot;程序标准格式&quot; <a class="header-anchor" href="#二、elf-linux-的-程序标准格式" aria-label="Permalink to &quot;二、ELF:Linux 的&quot;程序标准格式&quot;&quot;">​</a></h2><p>ELF(Executable and Linkable Format)是 Linux / BSD / Solaris 共用的标准。注意名字里那两个词——<strong>Executable(可执行)和 Linkable(可链接)</strong>,一种格式服务两个完全不同的阶段,这是 ELF 设计的精髓。三种文件都是 ELF:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.o    目标文件(可链接)</span></span>
<span class="line"><span>.so   共享库(可链接 + 可执行)</span></span>
<span class="line"><span>exec  可执行文件(可装载运行)</span></span></code></pre></div><h3 id="_2-1-物理结构" tabindex="-1">2.1 物理结构 <a class="header-anchor" href="#_2-1-物理结构" aria-label="Permalink to &quot;2.1 物理结构&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────┐</span></span>
<span class="line"><span>│   ELF Header     │ ← 16 字节魔数 + 元信息</span></span>
<span class="line"><span>├──────────────────┤</span></span>
<span class="line"><span>│  Program Header  │ ← 装载视图(execve 看的)</span></span>
<span class="line"><span>│      Table       │</span></span>
<span class="line"><span>├──────────────────┤</span></span>
<span class="line"><span>│      .text       │ ← 代码段(机器码)</span></span>
<span class="line"><span>│      .rodata     │ ← 只读数据(字符串字面量)</span></span>
<span class="line"><span>│      .data       │ ← 已初始化的全局变量</span></span>
<span class="line"><span>│      .bss        │ ← 未初始化的全局变量(占位,文件里 0 字节)</span></span>
<span class="line"><span>│      .symtab     │ ← 符号表</span></span>
<span class="line"><span>│      .rel.text   │ ← 重定位信息</span></span>
<span class="line"><span>│      .debug_info │ ← 调试信息(-g 时才有)</span></span>
<span class="line"><span>├──────────────────┤</span></span>
<span class="line"><span>│  Section Header  │ ← 链接视图(ld 看的)</span></span>
<span class="line"><span>│      Table       │</span></span>
<span class="line"><span>└──────────────────┘</span></span></code></pre></div><h3 id="_2-2-一份内容-两种视图-section-vs-segment" tabindex="-1">2.2 一份内容,两种视图:Section vs Segment <a class="header-anchor" href="#_2-2-一份内容-两种视图-section-vs-segment" aria-label="Permalink to &quot;2.2 一份内容,两种视图:Section vs Segment&quot;">​</a></h3><p>ELF 最有意思的设计是<strong>同一份内容,给两个读者准备了两张目录</strong>:</p><ul><li><strong>Section(节)= 链接视图</strong>——给链接器 ld 看的,粒度细:<code>.text</code>、<code>.data</code>、<code>.bss</code>、<code>.symtab</code>……链接器要精确知道每一块是什么才能合并、重定位</li><li><strong>Segment(段)= 装载视图</strong>——给内核 / 装载器看的,粒度粗:几个 section 按权限分组打包</li></ul><p>典型的 segment 划分:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>LOAD (R-X):  .text + .rodata     ← 只读可执行</span></span>
<span class="line"><span>LOAD (RW-):  .data + .bss        ← 可读可写</span></span>
<span class="line"><span>DYNAMIC:     .dynamic             ← 动态链接信息</span></span>
<span class="line"><span>INTERP:      .interp              ← 动态链接器路径</span></span></code></pre></div><p>为什么这么分?因为两个读者关心的事完全不同:<strong>链接时关心细节,装载时只关心权限</strong>——内核只需要知道&quot;这一块映射成 RX、那一块映射成 RW&quot;,里面是代码还是字符串,它不在乎。</p><h3 id="_2-3-解剖-elf-的工具箱" tabindex="-1">2.3 解剖 ELF 的工具箱 <a class="header-anchor" href="#_2-3-解剖-elf-的工具箱" aria-label="Permalink to &quot;2.3 解剖 ELF 的工具箱&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">file</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # 文件类型</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">readelf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # ELF Header</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">readelf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # Program Headers(segments)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">readelf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # Section Headers</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">readelf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 动态依赖</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                  # 符号表</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">objdump</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 反汇编</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">strings</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">             # 字符串</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ldd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                 # 动态库依赖树</span></span></code></pre></div><p>这几个命令值得现在就敲一遍——<strong>第一次亲眼看到自己程序的内脏,是建立心智模型最快的方式</strong>。</p><hr><h2 id="三、链接-把碎片拼成完整程序" tabindex="-1">三、链接:把碎片拼成完整程序 <a class="header-anchor" href="#三、链接-把碎片拼成完整程序" aria-label="Permalink to &quot;三、链接:把碎片拼成完整程序&quot;">​</a></h2><h3 id="_3-1-链接器在干什么" tabindex="-1">3.1 链接器在干什么 <a class="header-anchor" href="#_3-1-链接器在干什么" aria-label="Permalink to &quot;3.1 链接器在干什么&quot;">​</a></h3><p>编译是按文件独立进行的——<code>main.o</code> 里调用了 <code>printf</code>,但 printf 的实现不在这个文件里,编译器只能留个&quot;欠条&quot;(未定义符号)。链接器的工作就是<strong>收欠条、还欠条</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 符号解析:把&quot;引用 printf&quot;对应到&quot;libc 里的 printf 实现&quot;</span></span>
<span class="line"><span>2. 重定位:计算每个函数 / 全局变量的最终地址,改写所有引用</span></span>
<span class="line"><span>3. 合并 section:多个 .o 的 .text 合并成一个 .text</span></span>
<span class="line"><span>4. 生成 ELF</span></span></code></pre></div><p>链接错误就两种,全是欠条出了问题:<strong>undefined reference</strong>(欠条没人认——少链了库)、<strong>multiple definition</strong>(两个人都认领同一笔债——符号重复定义)。</p><h3 id="_3-2-静态链接-全打包带走" tabindex="-1">3.2 静态链接:全打包带走 <a class="header-anchor" href="#_3-2-静态链接-全打包带走" aria-label="Permalink to &quot;3.2 静态链接:全打包带走&quot;">​</a></h3><p>把所有依赖的 <code>.o</code> 和静态库 <code>.a</code> 全塞进一个可执行文件:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gcc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -static</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello.c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># -rwxr-xr-x 1 user user 1.2M hello   ← 1MB+,因为塞进了整个 libc</span></span></code></pre></div><p><strong>Go 默认就是静态链接——这就是为什么 Go 二进制 10MB 起步,但部署是&quot;扔过去就能跑&quot;的极致简单</strong>。</p><h3 id="_3-3-动态链接-运行时才借" tabindex="-1">3.3 动态链接:运行时才借 <a class="header-anchor" href="#_3-3-动态链接-运行时才借" aria-label="Permalink to &quot;3.3 动态链接:运行时才借&quot;">​</a></h3><p><code>.so</code> 共享库不打进二进制,运行时才加载:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gcc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello.c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># -rwxr-xr-x 1 user user  16K hello    ← 只有 16KB</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ldd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># linux-vdso.so.1</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># libc.so.6 =&gt; /lib/x86_64-linux-gnu/libc.so.6</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># /lib64/ld-linux-x86-64.so.2</span></span></code></pre></div><p>两条路线的取舍:</p><table tabindex="0"><thead><tr><th>维度</th><th>静态链接</th><th>动态链接</th></tr></thead><tbody><tr><td>文件大小</td><td>大(MB 级)</td><td>小(KB 级)</td></tr><tr><td>部署</td><td>扔过去就跑</td><td>目标机要有对应版本 .so,否则&quot;DLL 地狱&quot;</td></tr><tr><td>内存</td><td>每个进程一份 libc</td><td>多进程共享一份</td></tr><tr><td>库升级</td><td>重新链接</td><td>换 .so 即可(ABI 兼容前提下)</td></tr><tr><td>启动</td><td>快</td><td>慢一点(动态链接耗时)</td></tr><tr><td>代表</td><td>Go</td><td>C/C++ 默认</td></tr></tbody></table><hr><h2 id="四、动态链接的运行时细节" tabindex="-1">四、动态链接的运行时细节 <a class="header-anchor" href="#四、动态链接的运行时细节" aria-label="Permalink to &quot;四、动态链接的运行时细节&quot;">​</a></h2><h3 id="_4-1-ld-linux-so-最神秘的程序" tabindex="-1">4.1 ld-linux.so:最神秘的程序 <a class="header-anchor" href="#_4-1-ld-linux-so-最神秘的程序" aria-label="Permalink to &quot;4.1 ld-linux.so:最神秘的程序&quot;">​</a></h3><p>你以为 <code>./hello</code> 第一个跑的是 hello?错——<strong>内核装载完 hello 后,跳转的是动态链接器 ld-linux.so 的入口</strong>,由它加载所有 .so、解析完符号,才轮到你的程序:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./hello</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 等价于</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/lib64/ld-linux-x86-64.so.2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./hello</span></span></code></pre></div><p>ld-linux.so 本身的身份很拧巴——<strong>它是个动态库,但能直接执行</strong>。它的职责:解析 <code>.dynamic</code> 段看需要哪些 .so → mmap 加载进进程地址空间 → 解析符号(printf 在 libc.so 里的实际地址)→ 重定位 GOT / PLT 表 → 跳转到程序入口。</p><h3 id="_4-2-got-和-plt-动态链接的-间接表" tabindex="-1">4.2 GOT 和 PLT:动态链接的&quot;间接表&quot; <a class="header-anchor" href="#_4-2-got-和-plt-动态链接的-间接表" aria-label="Permalink to &quot;4.2 GOT 和 PLT:动态链接的&quot;间接表&quot;&quot;">​</a></h3><p>动态链接有个根本难题:<strong>编译时不知道 printf 的最终地址</strong>——每次运行地址都不同(ASLR,下面讲)。怎么 call 一个不知道地址的函数?答案是经典的间接层:<strong>调用不走直达,走跳板</strong>。</p><ul><li><strong>GOT(Global Offset Table)</strong>:全局符号的真实地址表</li><li><strong>PLT(Procedure Linkage Table)</strong>:函数跳转的&quot;跳板&quot;代码</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你的代码:call printf@plt</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>PLT 跳板:跳到 GOT 里 printf 对应的格子</span></span>
<span class="line"><span>   ↓ 第一次调用:</span></span>
<span class="line"><span>       格子里还没有真地址 → 触发动态链接器解析 → 把真地址填回 GOT</span></span>
<span class="line"><span>   ↓ 后续调用:</span></span>
<span class="line"><span>       格子里有真地址 → 直接跳,几乎零开销</span></span></code></pre></div><p>这个&quot;第一次才解析&quot;的机制叫<strong>懒绑定(lazy binding)</strong>——程序引用了 1000 个库函数,启动时一个都不解析,谁被调用了才解析谁。<strong>启动速度和按需开销的权衡,被一张表优雅地解决了</strong>。</p><h3 id="_4-3-ld-preload-运行时偷梁换柱" tabindex="-1">4.3 LD_PRELOAD:运行时偷梁换柱 <a class="header-anchor" href="#_4-3-ld-preload-运行时偷梁换柱" aria-label="Permalink to &quot;4.3 LD_PRELOAD:运行时偷梁换柱&quot;">​</a></h3><p>既然符号是运行时才解析的,就有操作空间——环境变量 <code>LD_PRELOAD</code> 让你的 .so <strong>优先于系统库</strong>被搜索:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 我写了个 my_malloc.so,里面定义了 malloc()</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">LD_PRELOAD</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">./my_malloc.so</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ./hello</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># hello 调用的 malloc 实际跑的是我的版本</span></span></code></pre></div><p>正经用途:内存分析(jemalloc / tcmalloc 替换默认分配器)、性能埋点、安全审计。不正经用途也很多——<strong>排查诡异行为时,记得看一眼环境变量里有没有 LD_PRELOAD</strong>。</p><hr><h2 id="五、装载-execve-把-elf-变成进程" tabindex="-1">五、装载:execve 把 ELF 变成进程 <a class="header-anchor" href="#五、装载-execve-把-elf-变成进程" aria-label="Permalink to &quot;五、装载:execve 把 ELF 变成进程&quot;">​</a></h2><h3 id="_5-1-execve-在干什么" tabindex="-1">5.1 execve 在干什么 <a class="header-anchor" href="#_5-1-execve-在干什么" aria-label="Permalink to &quot;5.1 execve 在干什么&quot;">​</a></h3><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">execve</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/bin/hello&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, argv, envp);</span></span></code></pre></div><p>内核做的事:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 读 ELF header,校验魔数</span></span>
<span class="line"><span>2. 清空当前进程的内存映射(原来的程序彻底没了)</span></span>
<span class="line"><span>3. 按 Program Header 用 mmap 把各 segment 映射进虚拟地址空间</span></span>
<span class="line"><span>4. 设置栈:argv / envp / auxv 推入栈</span></span>
<span class="line"><span>5. 找到 .interp 指定的动态链接器(/lib64/ld-linux-x86-64.so.2)</span></span>
<span class="line"><span>6. 跳转到动态链接器入口(注意:不是 main!)</span></span></code></pre></div><p>注意第 3 步用的是 mmap——<strong>装载不是把文件整个读进内存,而是建立映射</strong>,真正的代码页是执行到才缺页加载的。这就是为什么巨大的程序也能&quot;秒启动&quot;。</p><h3 id="_5-2-aslr-每次运行-地址全洗牌" tabindex="-1">5.2 ASLR:每次运行,地址全洗牌 <a class="header-anchor" href="#_5-2-aslr-每次运行-地址全洗牌" aria-label="Permalink to &quot;5.2 ASLR:每次运行,地址全洗牌&quot;">​</a></h3><p>每次运行,栈、堆、共享库的地址都不一样——这是 ASLR(地址空间随机化),目的是让攻击者无法预测地址来构造 buffer overflow 攻击:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./hello</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$!</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/maps</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 7f8a3c000000-7f8a3c023000 r--p ...  /libc.so.6</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># (再跑一次,地址全变)</span></span></code></pre></div><p>ASLR 对调试不太友好——断点地址每次都漂。好消息是 <strong>GDB 默认自动关掉 ASLR</strong>(<code>set disable-randomization on</code> 是默认值),所以你在 GDB 里看到的地址是稳定的——也因此,<strong>GDB 里能复现的地址,脱离 GDB 就不一定了</strong>。</p><h3 id="_5-3-pie-可执行文件自己也要能漂" tabindex="-1">5.3 PIE:可执行文件自己也要能漂 <a class="header-anchor" href="#_5-3-pie-可执行文件自己也要能漂" aria-label="Permalink to &quot;5.3 PIE:可执行文件自己也要能漂&quot;">​</a></h3><p>ASLR 要随机化可执行文件本身的地址,前提是<strong>这个文件能在任意地址运行</strong>——这就是 PIE(Position Independent Executable)。现代 GCC 默认开启:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">file</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ... ELF 64-bit LSB pie executable ...</span></span></code></pre></div><p>老的 non-PIE 程序装载地址固定在 0x400000——攻击者闭着眼都知道你的代码在哪,不安全。</p><hr><h2 id="六、main-之前-你以为的入口不是入口" tabindex="-1">六、main 之前:你以为的入口不是入口 <a class="header-anchor" href="#六、main-之前-你以为的入口不是入口" aria-label="Permalink to &quot;六、main 之前:你以为的入口不是入口&quot;">​</a></h2><p><code>main</code> 不是程序的真正入口——<strong><code>_start</code> 才是</strong>(在 crt0.o 里,链接器自动塞进来的)。从动态链接完成到 main 之间,还有一整段路:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ld-linux.so 完成动态链接</span></span>
<span class="line"><span>   ↓ 跳到 _start</span></span>
<span class="line"><span>_start:</span></span>
<span class="line"><span>   设置好 argc, argv, envp</span></span>
<span class="line"><span>   调用 __libc_start_main</span></span>
<span class="line"><span>__libc_start_main:</span></span>
<span class="line"><span>   1. 调用 .preinit_array 里的函数</span></span>
<span class="line"><span>   2. 调用 .init_array 里的函数(C++ 全局对象构造、glibc 初始化)</span></span>
<span class="line"><span>   3. 调用 main(argc, argv, envp)</span></span>
<span class="line"><span>   4. main 返回后,调用 exit()</span></span>
<span class="line"><span>   5. exit 调用 .fini_array 里的函数(析构)</span></span>
<span class="line"><span>   6. 调用 _exit syscall 真正退出</span></span></code></pre></div><h3 id="_6-1-c-全局对象-main-之前就跑了你的代码" tabindex="-1">6.1 C++ 全局对象:main 之前就跑了你的代码 <a class="header-anchor" href="#_6-1-c-全局对象-main-之前就跑了你的代码" aria-label="Permalink to &quot;6.1 C++ 全局对象:main 之前就跑了你的代码&quot;">​</a></h3><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Foo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Foo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() { </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">printf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;foo!</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">); } };</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Foo g_foo;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       // 在 main 之前构造</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> main</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() { </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">return</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; }</span></span></code></pre></div><p>输出 <code>foo!</code>——<strong>g_foo 的构造函数在 main 之前已经执行</strong>(就在上面的 .init_array 那一步)。</p><p>这里埋着 C++ 最著名的坑之一:<strong>多个翻译单元(.o 文件)之间,全局对象的构造顺序是未定义的</strong>。A.o 的全局对象构造时引用了 B.o 的全局对象,而后者可能还没构造——这就是「<strong>static initialization order fiasco</strong>」,出问题时症状是&quot;程序还没进 main 就崩了&quot;,新手根本想不到去 main 之前找。</p><h3 id="_6-2-atexit-退出时的回调" tabindex="-1">6.2 atexit:退出时的回调 <a class="header-anchor" href="#_6-2-atexit-退出时的回调" aria-label="Permalink to &quot;6.2 atexit:退出时的回调&quot;">​</a></h3><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">atexit</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(cleanup);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // main 返回 / 调 exit() 时,执行 cleanup</span></span></code></pre></div><p>一个容易翻车的细节:<strong><code>exit()</code> 会触发 atexit 回调和析构,<code>_exit()</code> 不会</strong>——后者直接 syscall 走人。日志没刷盘、文件没关干净,经常是有人调了 <code>_exit</code>(或者进程被信号杀了,同样不走 atexit)。</p><hr><h2 id="七、hello-world-到底加载了多少东西" tabindex="-1">七、Hello World 到底加载了多少东西 <a class="header-anchor" href="#七、hello-world-到底加载了多少东西" aria-label="Permalink to &quot;七、Hello World 到底加载了多少东西&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ldd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /bin/ls</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># linux-vdso.so.1</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># libselinux.so.1</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># libc.so.6</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># libpcre2-8.so.0</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># /lib64/ld-linux-x86-64.so.2</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/maps</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> wc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 几十行 mmap 区域</span></span></code></pre></div><p>最简单的程序也至少要加载:libc.so.6(C 标准库)、ld-linux.so(动态链接器)、vDSO(内核提供的快速 syscall,02 篇讲过)。<strong>复杂程序(Java / Python)一启动加载 200+ 个 .so——这就是 Java 冷启动慢的一大原因</strong>。</p><p>顺带一个进阶问题:两个 .so 都定义了 <code>init()</code> 怎么办?默认规则是<strong>按加载顺序,第一个定义的赢</strong>——大型程序里的定时炸弹。排查靠 <code>nm</code> 看符号、<code>ldd</code> 看加载顺序;根治靠符号版本控制(<code>.symver</code>)或加载隔离——<strong>Python 就是用 <code>dlopen(..., RTLD_LOCAL)</code> 隔离每个 C 扩展模块的符号</strong>,多个版本才能共存。</p><hr><h2 id="八、core-dump-死后的-全身快照" tabindex="-1">八、core dump:死后的&quot;全身快照&quot; <a class="header-anchor" href="#八、core-dump-死后的-全身快照" aria-label="Permalink to &quot;八、core dump:死后的&quot;全身快照&quot;&quot;">​</a></h2><p>程序段错误时,内核可以把进程的内存 + 寄存器完整 dump 成一个文件:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ulimit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> unlimited</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # 允许生成 core(很多发行版默认是 0!)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./crashy_program</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Segmentation fault (core dumped)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gdb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> crashy_program</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> core</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gdb</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bt</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                  # 看崩溃瞬间的调用栈</span></span></code></pre></div><p>漂亮的闭环:<strong>core dump 也是 ELF 格式</strong>——程序生是 ELF,死也是 ELF,同一套工具(readelf / gdb)从头管到尾。</p><p>容器里的坑:core dump 的去向由<strong>宿主机</strong>的 <code>/proc/sys/kernel/core_pattern</code> 决定,常被 systemd-coredump 收走——容器里翻遍了也找不到 core,要去宿主机找。</p><hr><h2 id="九、容器镜像-程序生命周期的-打包发行版" tabindex="-1">九、容器镜像:程序生命周期的&quot;打包发行版&quot; <a class="header-anchor" href="#九、容器镜像-程序生命周期的-打包发行版" aria-label="Permalink to &quot;九、容器镜像:程序生命周期的&quot;打包发行版&quot;&quot;">​</a></h2><p>理解了这一篇,Docker 镜像就没有神秘感了——它本质上就是<strong>把程序运行所需的一切打了个包</strong>:程序本身(ELF)+ 依赖的 .so + 配置 / 数据文件 + 一个最小的 rootfs。</p><p>为什么 Alpine 镜像能做到几 MB?三招,全是本篇讲过的知识:musl 替代 glibc(小 5 倍)、静态链接(干脆去掉 .so 依赖)、删掉文档和 locale。<strong>容器不是虚拟机,里面的程序还是 ELF 直接跑在宿主内核上</strong>——详见 25 篇容器底层。</p><hr><h2 id="十、踩坑提醒" tabindex="-1">十、踩坑提醒 <a class="header-anchor" href="#十、踩坑提醒" aria-label="Permalink to &quot;十、踩坑提醒&quot;">​</a></h2><ol><li><strong>以为 main 是入口</strong>——_start 才是,main 之前已经跑了一堆初始化代码</li><li><strong>以为静态链接没缺点</strong>——没法热升级库、二进制大、内存不共享</li><li><strong>部署失败不查 ldd</strong>——程序到目标机跑不起来,八成是缺 .so</li><li><strong>glibc 版本不兼容</strong>——新机器编译的二进制扔老机器,libc 版本太低直接挂</li><li><strong>假设 C++ 全局对象的构造顺序</strong>——跨 .o 顺序未定义,fiasco 级别的 bug</li><li><strong>不知道 ASLR</strong>——疑惑为什么地址每次都变,GDB 里稳定线上却不稳定</li><li><strong>动态链接器找不到符号</strong>——启动报错先查 GOT / PLT / LD_LIBRARY_PATH</li><li><strong>LD_PRELOAD 滥用</strong>——线上偷偷 hook,出问题排查极难</li><li><strong>不开 core dump</strong>——线上崩了没现场,<code>ulimit -c unlimited</code> 提前配好</li><li><strong>以为 Hello World 简单</strong>——背后几十个 syscall、几十个 .so</li><li><strong>发布前 strip 掉调试信息又不留符号文件</strong>——出事时栈都看不懂</li><li><strong>以为容器是虚拟机</strong>——容器只是 namespace,程序还是 ELF 直接跑</li></ol><hr><p>下一篇:<code>04-CPU视角.md</code>,讲程序员该懂的 CPU 知识——<strong>寄存器、流水线、多核、缓存层级</strong>(L1 到 DRAM 延迟差 100 倍)、<strong>乱序执行</strong>(CPU 比你想的&quot;狡猾&quot;得多)、<strong>SIMD 向量化</strong>(一条指令算一排数),以及为什么&quot;性能优化最后都归结为 cache 友好&quot;。</p>`,99)])])}const g=a(e,[["render",t]]);export{k as __pageData,g as default};
